import{_ as t,o as e,c as r,a1 as o}from"./chunks/framework.BwbI10pK.js";const q=JSON.parse('{"title":"浏览器原理与渲染","description":"","frontmatter":{},"headers":[],"relativePath":"browser/index.md","filePath":"browser/index.md"}'),i={name:"browser/index.md"};function l(n,a,s,u,h,d){return e(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="浏览器原理与渲染" tabindex="-1">浏览器原理与渲染 <a class="header-anchor" href="#浏览器原理与渲染" aria-label="Permalink to &quot;浏览器原理与渲染&quot;">​</a></h1><blockquote><p>副标题：从多进程架构到渲染管线，建立&quot;请求 → 像素&quot;的完整心智模型</p></blockquote><h2 id="模块定位" tabindex="-1">模块定位 <a class="header-anchor" href="#模块定位" aria-label="Permalink to &quot;模块定位&quot;">​</a></h2><p>很多前端工程师做性能优化时，第一反应是&quot;框架重复渲染&quot;或&quot;包体积太大&quot;，却忽略了真正的瓶颈往往在浏览器内部链路。本模块不把浏览器当作黑盒，而是拆开它的网络栈、HTML/CSS 解析器、V8 引擎、渲染管线与 GPU 合成，让你理解每一行代码如何最终变成屏幕上的像素。</p><p>只有建立&quot;从请求到像素&quot;的完整心智模型，才能把性能问题定位到具体阶段，选择正确的优化手段。</p><h2 id="核心主题" tabindex="-1">核心主题 <a class="header-anchor" href="#核心主题" aria-label="Permalink to &quot;核心主题&quot;">​</a></h2><ul><li><strong>多进程架构</strong>：浏览器进程、渲染器进程、GPU 进程、网络进程的职责划分与 IPC 协作</li><li><strong>渲染流水线</strong>：Style / Layout / Paint / Raster / Composite 五段的成本与触发条件</li><li><strong>资源加载</strong>：预加载扫描器、Fetch Priority、HTTP/2 / HTTP/3 对资源组织方式的影响</li><li><strong>GPU 合成</strong>：图层、Tile 光栅化、合成层提升条件与合成层爆炸</li><li><strong>性能指标</strong>：TTFB / LCP / INP / CLS 的拆解方法与优化方向</li></ul><h2 id="文章导览" tabindex="-1">文章导览 <a class="header-anchor" href="#文章导览" aria-label="Permalink to &quot;文章导览&quot;">​</a></h2><ul><li><a href="/browser/rendering-pipeline">渲染流水线：从 HTML 到像素</a> — 完整链路总览，理解每一阶段的输入与输出</li><li><a href="/browser/layout-thrashing">布局抖动的真相：Layout Thrashing 如何搞垮你的动画</a> — 强制同步布局的成因与 FastDOM 解法</li><li><a href="/browser/painting-rasterization">绘制与光栅化</a> — Paint 记录、Tile 光栅化与合成层机制</li></ul><h2 id="适用读者" tabindex="-1">适用读者 <a class="header-anchor" href="#适用读者" aria-label="Permalink to &quot;适用读者&quot;">​</a></h2><ul><li>中高级前端工程师，希望突破&quot;框架局部优化&quot;的视角局限</li><li>性能优化负责人，需要建立团队级的性能问题诊断框架</li><li>前端架构师，需要在技术选型时评估浏览器能力边界</li></ul>',11)])])}const p=t(i,[["render",l]]);export{q as __pageData,p as default};
